pub fn sum_even(numbers: &[i32]) -> i32 {
    numbers.iter()
        .filter(|&&n| n % 2 == 0)
        .sum()
}

use std::collections::HashMap;

pub fn group_by_first_char(words: &[&str]) -> HashMap<char, Vec<&str>> {
    words.iter()
        .filter(|w| !w.is_empty())
        .fold(HashMap::new(), |mut acc, &word| {
            let first = word.chars().next().unwrap();
            acc.entry(first).or_default().push(word);
            acc
        })
}
